import{_ as t,a,b as n,c as r,d as i}from"./chunks/编辑配置.T0puvWjh.js";import{_ as l,o as d,c as o,a2 as s}from"./chunks/framework.DnrXFDHb.js";const z=JSON.parse('{"title":"Telegram-Kanal hinzufügen","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/upload/telegram.md","filePath":"de-DE/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"de-DE/upload/telegram.md"};function c(u,e,g,m,p,b){return d(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="telegram-kanal-hinzufugen" tabindex="-1">Telegram-Kanal hinzufügen <a class="header-anchor" href="#telegram-kanal-hinzufugen" aria-label="Permalink to &quot;Telegram-Kanal hinzufügen&quot;">​</a></h1><h2 id="was-du-vorher-brauchst" tabindex="-1">Was du vorher brauchst <a class="header-anchor" href="#was-du-vorher-brauchst" aria-label="Permalink to &quot;Was du vorher brauchst&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Voraussetzung</th><th>Zweck</th></tr></thead><tbody><tr><td>Telegram-Konto</td><td>Für Bot und Speicherkanal.</td></tr><tr><td><code>@BotFather</code></td><td>Erstellt den Telegram-Bot.</td></tr><tr><td>Telegram-Kanal</td><td>Zielort, in dem Dateien gespeichert werden.</td></tr><tr><td><code>@userinfobot</code></td><td>Hilft beim Ermitteln der Kanal-<code>Chat ID</code>.</td></tr></tbody></table><h2 id="wo-hinzufugen" tabindex="-1">Wo hinzufügen <a class="header-anchor" href="#wo-hinzufugen" aria-label="Permalink to &quot;Wo hinzufügen&quot;">​</a></h2><ol><li>Öffne die Systemeinstellungen.</li><li>Gehe zu Upload-Einstellungen.</li><li>Klicke oben rechts auf Kanal hinzufügen.</li><li>Wähle <code>Telegram</code>.</li></ol><h2 id="feldubersicht" tabindex="-1">Feldübersicht <a class="header-anchor" href="#feldubersicht" aria-label="Permalink to &quot;Feldübersicht&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feld</th><th>Funktion</th><th>Erforderlich</th></tr></thead><tbody><tr><td>Kanalname</td><td>Ein gut erkennbarer Name für diesen Kanal, z. B. <code>Telegram Primary</code>.</td><td>Erforderlich</td></tr><tr><td>Aktiv</td><td>Aktiviert oder deaktiviert diesen Kanal.</td><td>Empfohlen</td></tr><tr><td>Bot Token</td><td>Token deines Telegram-Bots.</td><td>Erforderlich</td></tr><tr><td>Session ID (Chat ID)</td><td>ID des Telegram-Kanals.</td><td>Erforderlich</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Nur verwenden, wenn Telegram-Zugriffe instabil sind. Vollständige Proxy-URL inklusive <code>https://</code> eintragen.</td><td>Optional</td></tr><tr><td>Bemerkung</td><td>Notizen für spätere Wartung.</td><td>Optional</td></tr></tbody></table><h2 id="einrichtungsschritte" tabindex="-1">Einrichtungsschritte <a class="header-anchor" href="#einrichtungsschritte" aria-label="Permalink to &quot;Einrichtungsschritte&quot;">​</a></h2><h3 id="_1-telegram-bot-erstellen" tabindex="-1">1. Telegram-Bot erstellen <a class="header-anchor" href="#_1-telegram-bot-erstellen" aria-label="Permalink to &quot;1. Telegram-Bot erstellen&quot;">​</a></h3><ol><li>Öffne Telegram und suche nach <code>@BotFather</code>.</li><li>Öffne den Chat und klicke auf <code>Start</code>.</li><li>Sende <code>/newbot</code>.</li><li>Folge den Anweisungen und gib einen Anzeigenamen für den Bot ein.</li><li>Gib anschließend einen Bot-Benutzernamen ein. Der Name muss meistens auf <code>bot</code> enden.</li><li>Nach dem Erstellen gibt <code>@BotFather</code> ein Bot-Token zurück.</li></ol><p>Dieses Token trägst du in ImgBed als <code>Bot Token</code> ein.</p><p><img src="'+t+'" alt="Bot-Token speichern" loading="lazy"></p><h3 id="_2-kanal-erstellen" tabindex="-1">2. Kanal erstellen <a class="header-anchor" href="#_2-kanal-erstellen" aria-label="Permalink to &quot;2. Kanal erstellen&quot;">​</a></h3><ol><li>Klicke in Telegram auf Neuer Kanal.</li><li>Gib einen Kanalnamen ein.</li><li>Schließe die Erstellung ab.</li></ol><p>Öffentliche und private Kanäle funktionieren beide.</p><p><img src="'+a+'" alt="Kanal erstellen" loading="lazy"></p><h3 id="_3-bot-zum-kanal-hinzufugen" tabindex="-1">3. Bot zum Kanal hinzufügen <a class="header-anchor" href="#_3-bot-zum-kanal-hinzufugen" aria-label="Permalink to &quot;3. Bot zum Kanal hinzufügen&quot;">​</a></h3><ol><li>Öffne den gerade erstellten Kanal.</li><li>Öffne die Kanaleinstellungen.</li><li>Füge ein Mitglied oder einen Administrator hinzu.</li><li>Suche nach dem Benutzernamen deines Bots.</li><li>Füge den Bot zum Kanal hinzu.</li></ol><p>Für zuverlässige Uploads solltest du dem Bot Administratorrechte geben.</p><p><img src="'+n+'" alt="Bot in den Kanal einladen" loading="lazy"></p><h3 id="_4-kanal-id-mit-user-info-get-id-idbot-abrufen" tabindex="-1">4. Kanal-ID mit User Info - Get ID - IDbot abrufen <a class="header-anchor" href="#_4-kanal-id-mit-user-info-get-id-idbot-abrufen" aria-label="Permalink to &quot;4. Kanal-ID mit User Info - Get ID - IDbot abrufen&quot;">​</a></h3><ol><li>Suche in Telegram nach <code>@userinfobot</code>. Der Anzeigename lautet meist <code>User Info - Get ID - IDbot</code>.</li><li>Öffne den Chat und klicke auf <code>Start</code>.</li><li>Wähle in den Bot-Optionen <code>Channel</code>.</li><li>Wähle im Nachrichtenpicker den Zielkanal aus und sende ihn an <code>@userinfobot</code>.</li><li>Wenn <code>@userinfobot</code> das Ergebnis zurückgibt, kopiere die Zahl bei <code>Id: -100...</code>.</li></ol><p>Die Zahl mit <code>-100</code> am Anfang ist die <code>Session ID (Chat ID)</code>, die ImgBed braucht.</p><p><img src="'+r+'" alt="Kanal-ID abrufen" loading="lazy"></p><h3 id="_5-telegram-kanal-in-imgbed-ausfullen" tabindex="-1">5. Telegram-Kanal in ImgBed ausfüllen <a class="header-anchor" href="#_5-telegram-kanal-in-imgbed-ausfullen" aria-label="Permalink to &quot;5. Telegram-Kanal in ImgBed ausfüllen&quot;">​</a></h3><p>Kehre zum Konfigurationsdialog zurück und trage die Werte ein:</p><table tabindex="0"><thead><tr><th>UI-Feld</th><th>Wert</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Eigener Kanalname, z. B. <code>TelegramPrimary</code>.</td></tr><tr><td>Aktiv</td><td>Empfohlen.</td></tr><tr><td>Bot Token</td><td>Das Bot-Token von <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>Die von <code>@userinfobot</code> zurückgegebene Zahl <code>-100...</code>.</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Nur bei Bedarf, z. B. <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Bemerkung</td><td>Optionale Notizen.</td></tr></tbody></table><p>Klicke anschließend auf Speichern.</p><p><img src="'+i+`" alt="Konfiguration bearbeiten" loading="lazy"></p><h2 id="prufung" tabindex="-1">Prüfung <a class="header-anchor" href="#prufung" aria-label="Permalink to &quot;Prüfung&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prüfung</th><th>So prüfst du es</th></tr></thead><tbody><tr><td>Kanalkarte erscheint</td><td>Nach dem Speichern sollte in den Upload-Einstellungen eine Telegram-Kanalkarte sichtbar sein.</td></tr><tr><td>Kanal lässt sich aktivieren</td><td>Der Aktiv-Schalter bleibt eingeschaltet.</td></tr><tr><td>Konfiguration ist gespeichert</td><td>Die Detailansicht zeigt, dass Bot Token und Chat ID gespeichert wurden.</td></tr><tr><td>Upload funktioniert</td><td>Lade ein Testbild hoch und prüfe, ob es im Zielkanal von Telegram erscheint.</td></tr></tbody></table><h2 id="kurzcheck" tabindex="-1">Kurzcheck <a class="header-anchor" href="#kurzcheck" aria-label="Permalink to &quot;Kurzcheck&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bot mit @BotFather erstellen</span></span>
<span class="line"><span>-&gt; Bot Token speichern</span></span>
<span class="line"><span>-&gt; Telegram-Kanal erstellen</span></span>
<span class="line"><span>-&gt; Bot zum Kanal hinzufügen und Administratorrechte geben</span></span>
<span class="line"><span>-&gt; @userinfobot suchen und Channel wählen</span></span>
<span class="line"><span>-&gt; Eine Nachricht aus dem Kanal an @userinfobot weiterleiten</span></span>
<span class="line"><span>-&gt; Zurückgegebene Id: -100... kopieren</span></span>
<span class="line"><span>-&gt; Bot Token und Chat ID in ImgBed eintragen</span></span>
<span class="line"><span>-&gt; Speichern und Testbild hochladen</span></span></code></pre></div><h2 id="referenzen" tabindex="-1">Referenzen <a class="header-anchor" href="#referenzen" aria-label="Permalink to &quot;Referenzen&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const B=l(h,[["render",c]]);export{z as __pageData,B as default};
